import{_ as a,o as n,c as i,ag as t}from"./chunks/framework.Dcoxob_B.js";const c=JSON.parse('{"title":"会话管理","description":"","frontmatter":{"_rawMarkdown":"# 会话管理\\n\\nSession 负责管理对话消息、记录上下文使用、提取长期记忆。\\n\\n## 概览\\n\\n**生命周期**：创建 → 交互 → 提交\\n\\n通过 session_id 获取会话时，默认不会自动创建不存在的会话；如果需要自动创建，请显式使用 `client.get_session(..., auto_create=True)`。\\n\\n```python\\nsession = client.session(session_id=\\"chat_001\\")\\nsession.add_message(\\"user\\", [TextPart(\\"...\\")])\\nsession.commit()\\n```\\n\\n## 核心 API\\n\\n| 方法 | 说明 |\\n|------|------|\\n| `add_message(role, parts)` | 添加消息 |\\n| `used(contexts, skill)` | 记录使用的上下文/技能 |\\n| `commit()` | 提交：归档（同步） + 摘要生成和记忆提取（异步后台） |\\n| `get_task(task_id)` | 查询后台任务状态 |\\n\\n### add_message\\n\\n```python\\nsession.add_message(\\n    \\"user\\",\\n    [TextPart(\\"How to configure embedding?\\")]\\n)\\n\\nsession.add_message(\\n    \\"assistant\\",\\n    [\\n        TextPart(\\"Here\'s how...\\"),\\n        ContextPart(uri=\\"viking://user/memories/profile.md\\"),\\n    ]\\n)\\n```\\n\\n### used\\n\\n```python\\n# 记录使用的上下文\\nsession.used(contexts=[\\"viking://user/memories/profile.md\\"])\\n\\n# 记录使用的技能\\nsession.used(skill={\\n    \\"uri\\": \\"viking://agent/skills/code-search\\",\\n    \\"input\\": \\"search config\\",\\n    \\"output\\": \\"found 3 files\\",\\n    \\"success\\": True\\n})\\n```\\n\\n### commit\\n\\n```python\\nresult = session.commit()\\n# {\\n#   \\"status\\": \\"accepted\\",\\n#   \\"task_id\\": \\"uuid-xxx\\",\\n#   \\"archive_uri\\": \\"viking://session/.../history/archive_001\\",\\n#   \\"archived\\": True\\n# }\\n\\n# 查询后台任务进度\\ntask = client.get_task(result[\\"task_id\\"])\\n# task[\\"status\\"]: \\"pending\\" | \\"running\\" | \\"completed\\" | \\"failed\\"\\n# sum(task[\\"result\\"][\\"memories_extracted\\"].values()): 3\\n```\\n\\n## 消息结构\\n\\n### Message\\n\\n```python\\n@dataclass\\nclass Message:\\n    id: str              # msg_{UUID}\\n    role: str            # \\"user\\" | \\"assistant\\"\\n    parts: List[Part]    # 消息部分\\n    created_at: datetime\\n```\\n\\n### Part 类型\\n\\n| 类型 | 说明 |\\n|------|------|\\n| `TextPart` | 文本内容 |\\n| `ContextPart` | 上下文引用（URI + 摘要） |\\n| `ToolPart` | 工具调用（输入 + 输出） |\\n\\n## 压缩策略\\n\\n### 归档流程\\n\\ncommit() 分两阶段执行：\\n\\n**Phase 1（同步，立即完成）**：\\n1. 递增 compression_index\\n2. 写入消息到归档目录（`messages.jsonl`）\\n3. 清空当前消息列表\\n4. 返回 `task_id`\\n\\n**Phase 2（异步后台）**：\\n5. 生成结构化摘要（LLM）→ 写入 `.abstract.md` 和 `.overview.md`\\n6. 提取长期记忆\\n7. 更新 active_count\\n8. 写入 `.done` 完成标记\\n\\n### 摘要格式\\n\\n```markdown\\n# 会话摘要\\n\\n**一句话概述**: [主题]: [意图] | [结果] | [状态]\\n\\n## Analysis\\n关键步骤列表\\n\\n## Primary Request and Intent\\n用户的核心目标\\n\\n## Key Concepts\\n关键技术概念\\n\\n## Pending Tasks\\n未完成的任务\\n```\\n\\n## 记忆提取\\n\\n### 8 种分类\\n\\n| 分类 | 归属 | 说明 | 可合并 |\\n|------|------|------|--------|\\n| **profile** | user | 用户身份/属性 | ✅ |\\n| **preferences** | user | 用户偏好 | ✅ |\\n| **entities** | user | 实体（人/项目） | ✅ |\\n| **events** | user | 事件/决策 | ❌ |\\n| **cases** | agent | 问题+解决方案 | ❌ |\\n| **patterns** | agent | 可复用流程 | ✅ |\\n| **tools** | agent | 工具使用经验与最佳实践 | ✅ |\\n| **skills** | agent | 技能执行经验与工作流策略 | ✅ |\\n\\n### 提取流程\\n\\n```\\n消息 → LLM 提取 → 候选记忆\\n         ↓\\n向量预过滤 → 找相似记忆\\n         ↓\\nLLM 去重决策 → candidate(skip/create/none) + item(merge/delete)\\n         ↓\\n写入 AGFS → 向量化\\n```\\n\\n### 去重决策\\n\\n| 层级 | 决策 | 说明 |\\n|------|------|------|\\n| Candidate | `skip` | 候选记忆重复，直接跳过 |\\n| Candidate | `create` | 创建候选记忆；必要时先删除冲突旧记忆 |\\n| Candidate | `none` | 不创建候选记忆，只处理已有记忆 |\\n| Existing item | `merge` | 将候选内容合并到指定已有记忆 |\\n| Existing item | `delete` | 删除冲突的已有记忆 |\\n\\n## 存储结构\\n\\n```\\nviking://session/{session_id}/\\n├── messages.jsonl            # 当前消息\\n├── .abstract.md              # 当前摘要\\n├── .overview.md              # 当前概览\\n├── history/\\n│   ├── archive_001/\\n│   │   ├── messages.jsonl    # Phase 1 写入\\n│   │   ├── .abstract.md      # Phase 2 写入（后台）\\n│   │   ├── .overview.md      # Phase 2 写入（后台）\\n│   │   └── .done             # Phase 2 完成标记\\n│   └── archive_NNN/\\n└── tools/\\n    └── {tool_id}/tool.json\\n\\nviking://user/memories/\\n├── profile.md                # 追加式用户画像\\n├── preferences/\\n├── entities/\\n└── events/\\n\\nviking://agent/memories/\\n├── cases/\\n├── patterns/\\n├── tools/\\n└── skills/\\n```\\n\\n## 相关文档\\n\\n- [架构概述](./01-architecture.md) - 系统整体架构\\n- [上下文类型](./02-context-types.md) - 三种上下文类型\\n- [上下文提取](./06-extraction.md) - 提取流程\\n- [上下文层级](./03-context-layers.md) - L0/L1/L2 模型\\n"},"headers":[],"relativePath":"zh/concepts/08-session.md","filePath":"zh/concepts/08-session.md","lastUpdated":1775135341000}'),e={name:"zh/concepts/08-session.md"};function l(p,s,h,d,r,o){return n(),i("div",null,[...s[0]||(s[0]=[t("",38)])])}const g=a(e,[["render",l]]);export{c as __pageData,g as default};
